mapper.select:
SELECT id, title, SUBSTRING(content, 1, 200) AS content, category_id, user_id, create_time, update_time
FROM document
WHERE user_id = #{userId}

    AND category_id = #{categoryId}


    AND MATCH(title, content) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)

AND is_deleted = 0
ORDER BY update_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM document WHERE user_id = #{userId} AND is_deleted = 0
AND category_id = #{categoryId}
AND MATCH(title, content) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)

mapper.update:
UPDATE document
SET is_deleted = 0, deleted_at = NULL
WHERE id = #{id}

mapper.select:
SELECT id, title, content, category_id, user_id, create_time, update_time, is_deleted, deleted_at
FROM document
WHERE id = #{id}
